<section class="labs-flow-grid"><article class="labs-card"><h2>Task progress</h2><div class="labs-stage40-task-path"><?php foreach ($context['tasks'] as $task): $dbTaskId = (string)($task['db_id'] ?? $task['id'] ?? ''); $proofs = $context['proofs_by_task'][$dbTaskId] ?? []; $status = $proofs ? (string)($proofs[0]['status'] ?? 'recorded') : 'not started'; ?><div class="labs-stage40-task-node"><span><?php echo $status === 'approved' ? '✓' : '•'; ?></span><div><strong><?php echo htmlspecialchars((string)$task['title'], ENT_QUOTES, 'UTF-8'); ?></strong><small><?php echo htmlspecialchars($status, ENT_QUOTES, 'UTF-8'); ?></small></div></div><?php endforeach; if (!$context['tasks']): ?><p class="labs-muted">No task rows available.</p><?php endif; ?></div></article><article class="labs-card"><h2>Receipts and rewards</h2><div class="labs-panel-list"><?php foreach ($context['receipts'] as $receipt): ?><div class="labs-panel-item"><span class="labs-mini-icon">A</span><div><strong><?php echo htmlspecialchars((string)$receipt['receipt_type'], ENT_QUOTES, 'UTF-8'); ?></strong><p><?php echo htmlspecialchars((string)$receipt['public_id'], ENT_QUOTES, 'UTF-8'); ?></p></div></div><?php endforeach; foreach ($context['rewards'] as $reward): ?><div class="labs-panel-item"><span class="labs-mini-icon">R</span><div><strong><?php echo htmlspecialchars((string)($reward['reward_label'] ?: 'Simulated reward'), ENT_QUOTES, 'UTF-8'); ?></strong><p><?php echo htmlspecialchars((string)$reward['status'], ENT_QUOTES, 'UTF-8'); ?> · no wallet write</p></div></div><?php endforeach; if (!$context['receipts'] && !$context['rewards']): ?><p class="labs-muted">No receipts or reward events yet.</p><?php endif; ?></div></article></section>
